module top_module(
    output reg alt_Q,
    input S,
    input R,
    input D,
    input G,
    input E
);parameter [0:0] INIT = 1'b0;
    initial alt_Q = INIT;
    always @*
      begin
        if (!R) 
          alt_Q <= 1'b0;
        else if (!S) 
          alt_Q <= 1'b1;
        else if (E && !G) 
          alt_Q <= D;
      end
endmodule
